import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshProducts, updateProductQuantity }) => {
    const [movement, setMovement] = useState({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
    const [products, setProducts] = useState([]);

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
                setProducts(response.data);
            } catch (error) {
                console.error("Erro ao buscar produtos:", error);
            }
        };

        fetchProducts();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        await axios.post('http://127.0.0.1:8000/api/movimentacoes/', movement);
        updateProductQuantity(movement.produto, movement.tipo_movimentacao, parseInt(movement.quantidade));
        refreshProducts();
        setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
    };

    return (
        <form onSubmit={handleSubmit}>
            <select name="produto" onChange={(e) => setMovement({ ...movement, produto: e.target.value })}>
                {products.map((p) => <option key={p.id} value={p.id}>{p.nome}</option>)}
            </select>
            <button type="submit">Registrar</button>
        </form>
    );
};

export default StockMovementForm;
